shape.script:
function getHandles(params) {
    return {
        radius: [params.radius, 0],
        tail: [0, -(params.radius*params.tail/100)]
    }
}

function getPath(params) {
    let width = params.radius;
    let height = params.radius;
    let tail = params.tail;
    let tailWidth = params.tailWidth;
    let squeeze = params.squeeze;
    let cw = 0.551915024494 * width;
    let ch = 0.551915024494 * height;
    if( tailWidth > 0.001 ) {
        return [
            {
                in:[-width/squeeze,-height*tail/(squeeze*100)],
                p:[-width*tailWidth/100,-height*tail/100]
            },
            {
                p:[width*tailWidth/100,-height*tail/100],
                out:[width/squeeze,-height*tail/(squeeze*100)]
            },
            {
                in:[width,-ch], // *tail/100
                p:[width,0],
                out:[width,ch]
            },
            {
                in:[cw,height],
                p:[0,height],
                out:[-cw,height]
            },
            {
                in:[-width,ch],
                p:[-width,0],
                out:[-width,-ch] // *tail/100
            },
            {closed:true}
        ];
    } else {
        return [
            {
                in:[-width/squeeze,-height*tail/(squeeze*100)],
                p:[0,-height*tail/100],
                out:[width/squeeze,-height*tail/(squeeze*100)]
            },
            {
                in:[width,-ch], // *tail/100
                p:[width,0],
                out:[width,ch]
            },
            {
                in:[cw,height],
                p:[0,height],
                out:[-cw,height]
            },
            {
                in:[-width,ch],
                p:[-width,0],
                out:[-width,-ch] // *tail/100
            },
            {closed:true}
        ];
    }
}
